Parameters.string:
IF sObjectId!='' { // set request body DYNAMIC agent_Details_update agent_Details_update.KAA__status__c = 'false' reqBody = "{agent_Details_update.asJSON()}"
existingUserProxy = GetRESTProxy() existingUserProxy.ContentType = "application/json" // set content type
// set Authorization ASSIGN requestAuth = "Bearer " requestAuth.append("{access_token}") existingUserProxy.AddHeader("Authorization",requestAuth) existingUserProxy.ContentType = "application/json"
ASSIGN SobjectName = "KAA__CxoneData__c" //set sobject name ASSIGN salesforcesobjectURI = "{salesforceBaseURI}/services/data/v58.0/sobjects/{SobjectName}/{sObjectId}" // set endpoint url existingUserProxy.MakeRestRequest(salesforcesobjectURI, reqBody ,0, "PATCH")
}

//User Authentication
ASSIGN global:access_token = "" // assign global varible for set access token ASSIGN global:sObjectId = "" // assign global varible for set id
ASSIGN global:salesforceBaseURI = "TO-BE-FILLED-IN" // set baseurl
// set credentials ASSIGN salesforcekey ="{salesforce_key}" ASSIGN salesforcesecret ="{salesforce_secret}" ASSIGN salesforceusername ="{salesforce_username}" ASSIGN salesforcepassword ="{salesforce_password}"
// urlencoded form ASSIGN salesforcekey=salesforcekey.urlencode ASSIGN salesforcesecret=salesforcesecret.urlencode ASSIGN salesforceusername=salesforceusername.urlencode ASSIGN salesforcepassword=salesforcepassword.urlencode
tokenproxy=GetRESTProxy()
//create local variable and append credentials ASSIGN tokenRequestParms="" tokenRequestParms.append("grant_type=password") tokenRequestParms.append("&client_id={salesforcekey}") tokenRequestParms.append("&client_secret={salesforcesecret}") tokenRequestParms.append("&username={salesforceusername}") tokenRequestParms.append("&password={salesforcepassword}")
ASSIGN salesforceAuthURI="{salesforceBaseURI}/services/oauth2/token" // set endpoint url tokenResult = tokenproxy.MakeRestRequest(salesforceAuthURI, tokenrequestParms, 0, "POST") //call api and store responsed in local variable
// check status code and get access token IF tokenproxy.StatusCode = 200 { access_token = "{tokenResult.access_token.$value}" }

// Insert the records after authentication IF access_token!='' { // set request body DYNAMIC agent_Details agent_Details.KAA__contact__c = "{contactid}" agent_Details.KAA__agentId__c = "{agentid}" agent_Details.KAA__status__c = "true" agent_Details.KAA__screenPopup__c="false" agent_Details.KAA__customData__c="{customdata_string}" requestBody = "{agent_Details.asJSON()}"
existingUserProxy = GetRESTProxy() existingUserProxy.ContentType = "application/json" // set content type
// set Authorization ASSIGN requestAuth = "Bearer " requestAuth.append("{access_token}") existingUserProxy.AddHeader("Authorization",requestAuth) existingUserProxy.ContentType = "application/json"
ASSIGN SobjectName = "KAA__CxoneData__c" //set sobject name ASSIGN salesforceSobjectURI = "{salesforceBaseURI}/services/data/v58.0/sobjects/{SobjectName}" //set endpoint url responsedBody = existingUserProxy.MakeRestRequest(salesforceSobjectURI, requestBody ,0, "POST") //ASSIGN global:bearerToken = "{global:existingResult.autoSuggestResults}"
sObjectId = "{responsedBody.id.$value}"
}

